import { Link, useNavigate } from 'react-router-dom';
import { MapPin, Search } from 'lucide-react';

const Home = () => {
  const navigate = useNavigate();

  const handleSearchClick = () => {
    navigate('/projects');
  };

  return (
    <div className="bg-[#0a0a0a] min-h-screen">
      <div className="container-custom pt-32 pb-20">
        
        {/* EST. 2010 line */}
        <div className="text-center mb-4">
          <span className="text-gray-500 text-sm tracking-wide">EST. 2010 — TRUSTED REAL ESTATE</span>
        </div>

        {/* WELCOME TO SWABHAGYA REALTY - Gold color */}
        <div className="text-center mb-3">
          <h2 className="text-[#c8a45e] text-sm uppercase tracking-[3px] font-medium">
            WELCOME TO SWABHAGYA REALTY
          </h2>
        </div>

        {/* Main Heading */}
        <div className="text-center mb-4">
          <h1 className="text-4xl md:text-5xl font-bold text-white">
            Find Your Perfect
            <span className="block text-[#c8a45e]">Property in Nashik</span>
          </h1>
        </div>

        {/* Description */}
        <div className="text-center mb-8">
          <p className="text-gray-400 text-base max-w-md mx-auto">
            We help you find the right space that fits your lifestyle and future.
          </p>
        </div>

        {/* Buttons */}
        <div className="flex justify-center gap-4 mb-12">
          <Link to="/projects">
            <button className="bg-[#c8a45e] text-black px-6 py-2 rounded-md text-sm font-medium hover:bg-[#b8923a] transition">
              Explore Properties →
            </button>
          </Link>
          <Link to="/contact">
            <button className="border border-gray-600 text-white px-6 py-2 rounded-md text-sm font-medium hover:bg-white hover:text-black transition">
              Contact Us
            </button>
          </Link>
        </div>

        {/* Location and Search Row */}
        <div className="flex justify-center items-center gap-2 text-sm flex-wrap">
          <div className="flex items-center gap-1 text-gray-400">
            <MapPin size={14} />
            <span>Nashik, Maharashtra</span>
          </div>
          <div className="text-gray-600">→</div>
          <div className="text-gray-400">Property Type</div>
          <div className="text-gray-600">→</div>
          <div className="text-gray-400">Max Budget</div>
          <button 
            onClick={handleSearchClick}
            className="bg-[#c8a45e] text-black px-4 py-1.5 rounded-md text-sm flex items-center gap-1 ml-2 hover:bg-[#b8923a] transition"
          >
            <Search size={14} /> Search Properties
          </button>
        </div>

      </div>
    </div>
  );
};

export default Home;
